import * as React from 'react';
import { render } from '@testing-library/react';
import AiCommonColorful from '../icons/AiCommonColorful';
function checkFillAndId(paths, defs, prefix) {
    if (paths.length > 0) {
        expect(paths[0].getAttribute('fill')).toBe(`url(#${prefix}__icon_ai-common_colorful__a)`);
    }
    if (paths.length > 1) {
        expect(paths[1].getAttribute('fill')).toBe(`url(#${prefix}__icon_ai-common_colorful__b)`);
    }
    if (defs.length > 0) {
        expect(defs[0].getAttribute('id')).toBe(`${prefix}__icon_ai-common_colorful__a`);
    }
    if (defs.length > 1) {
        expect(defs[1].getAttribute('id')).toBe(`${prefix}__icon_ai-common_colorful__b`);
    }
}
describe('dynamic id', () => {
    test('should be unique and fill should be correct', () => {
        let wrapper = render(React.createElement(AiCommonColorful, null));
        // 首次渲染
        let paths = wrapper.container.querySelectorAll('svg path');
        let defs = wrapper.container.querySelectorAll('svg defs linearGradient');
        checkFillAndId(paths, defs, 'u1');
        // 重新渲染
        wrapper.rerender(React.createElement(AiCommonColorful, null));
        paths = wrapper.container.querySelectorAll('svg path');
        defs = wrapper.container.querySelectorAll('svg defs linearGradient');
        checkFillAndId(paths, defs, 'u1');
        // 卸载后重新渲染
        wrapper.unmount();
        wrapper = render(React.createElement(AiCommonColorful, null));
        paths = wrapper.container.querySelectorAll('svg path');
        defs = wrapper.container.querySelectorAll('svg defs linearGradient');
        checkFillAndId(paths, defs, 'u2');
    });
});
